mapper.select:
SELECT cs.id, cs.class_id, cs.day_of_week, cs.period, cs.subject
FROM course_schedule cs
WHERE cs.class_id = #{classId}
AND cs.day_of_week = #{dayOfWeek}
AND cs.period = #{period}
AND cs.is_deleted = 0

    AND cs.id != #{excludeId}

LIMIT 1

SELECT cs.id, cs.teacher_id, cs.day_of_week, cs.period, cs.subject, c.class_name
FROM course_schedule cs
LEFT JOIN class_entity c ON cs.class_id = c.id
WHERE cs.teacher_id = #{teacherId}
AND cs.day_of_week = #{dayOfWeek}
AND cs.period = #{period}
AND cs.is_deleted = 0

    AND cs.id != #{excludeId}

LIMIT 1
